import{_ as o,o as a,c as t,a3 as r}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"52. Reasonable Additional Hours","description":"","frontmatter":{"title":"52. Reasonable Additional Hours","eba":"Health Allied & Managers Admin 2021-2025","topics":["hours","overtime"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/hours-of-work/52-reasonable-additional-hours.md","filePath":"ebas/has-managers-admin/common-terms/hours-of-work/52-reasonable-additional-hours.md"}'),n={name:"ebas/has-managers-admin/common-terms/hours-of-work/52-reasonable-additional-hours.md"};function s(i,e,m,l,h,d){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="_52-reasonable-additional-hours" tabindex="-1">52. Reasonable Additional Hours <a class="header-anchor" href="#_52-reasonable-additional-hours" aria-label="Permalink to &quot;52. Reasonable Additional Hours&quot;">​</a></h1><p><strong>52.1</strong> Subject to subclause 52.2, an Employer may require an Employee to work reasonable additional hours at the appropriate overtime rate as defined in <a href="/eba/ebas/has-managers-admin/common-terms/employment-types/25-fixed-term-employment.html">clause 25</a> of Section 2 (Overtime) and <a href="/eba/ebas/has-managers-admin/common-terms/preliminary/10-best-practice-employment-commitment.html">clause 10</a> of Section 3 (Overtime) of the Agreement.</p><p><strong>52.2</strong> An Employee may refuse to work overtime in circumstances where the working of such overtime would result in the Employee working hours which are unreasonable having regard to:</p><p><strong>(a)</strong> any risk to Employee health and safety arising from the additional hours;</p><p><strong>(b)</strong> the Employee&#39;s personal circumstances, including family responsibilities;</p><p><strong>(c)</strong> the needs of the workplace or enterprise in which the Employee is employed;</p><p><strong>(d)</strong> whether the Employee is entitled to receive overtime payments, penalty rates or other compensation for, or a level of remuneration that reflects an expectation of, working additional hours</p><p><strong>(e)</strong> the notice (if any) given by the Employer of the overtime and by the Employee of his or her intention to refuse it;</p><p><strong>(f)</strong> the usual patterns of work in the industry, or the part of the industry, in which the Employee works;</p><p><strong>(g)</strong> the nature of the Employee’s role, and the Employee’s level of responsibility;</p><p><strong>(h)</strong> whether the additional hours are in accordance with an averaging arrangement agreed to by the Employer and Employee under clause 22 of Section 2 and <a href="/eba/ebas/has-managers-admin/common-terms/preliminary/7-commencement-date-and-period-of-operation.html">clause 7</a> of Section 3 (Hours of Work); and any other relevant matter.</p><p>PART G – LEAVE AND PUBLIC HOLIDAYS</p><p>Plain language terms: reasonable OT, reasonable overtime.</p>',13)])])}const u=o(n,[["render",s]]);export{c as __pageData,u as default};
